   ============================================ */

const PAGE_SIZE_OPTIONS = [25, 50, 100];

export function ActivityTable() {
  const [data, setData] = useState<{
    items: Array<{
      id: string;
      projectId: string;
      eventType: ProjectEventType;
      title: string;
      description: string | null;
      actorName: string;
      createdAt: Date | string;
      project: { id: string; name: string; projectCode: string } | null;
    }>;
    total: number;
    page: number;
    pageSize: number;
    totalPages: number;
  } | null>(null);

  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [searchInput, setSearchInput] = useState("");
  const hasFetched = useRef(false);

  useEffect(() => {
    let active = true;
    (async () => {
      const result = await getActivityAction({
        page,
        pageSize,
        search: search || undefined,
      });
      if (!active) return;
      setData(result);
    })();
    return () => { active = false };
  }, [page, pageSize, search]);

  // Debounce search
  useEffect(() => {
    if (!hasFetched.current) {
      hasFetched.current = true;
      return;
    }
    const timer = setTimeout(() => {
      setSearch(searchInput);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  }, [searchInput]);

  const items = data?.items ?? [];
  const total = data?.total ?? 0;
  const totalPages = data?.totalPages ?? 0;
  const isLoading = !data;

  return (
    <div className="space-y-4">
      {/* Search */}
      <div className="relative max-w-sm">
        <Search className="pointer-events-none absolute start-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <Input
          type="search"
          placeholder="بحث في النشاط..."
          className="ps-9"
          value={searchInput}
          onChange={(e) => setSearchInput(e.target.value)}
          aria-label="بحث في النشاط"
        />
      </div>

      {/* Events List */}
      {isLoading ? (
        <div className="space-y-2">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="flex items-center gap-4 border-b p-4">
              <Skeleton className="h-8 w-8 rounded-full" />
              <div className="flex-1 space-y-2">
                <Skeleton className="h-4 w-48" />
                <Skeleton className="h-3 w-32" />
              </div>
            </div>
          ))}
        </div>
      ) : items.length === 0 ? (
        <div className="rounded-xl border bg-card">
          <EmptyState
            icon={ActivityIcon}
            title={search ? "لا توجد نتائج" : "لا يوجد نشاط بعد"}
            description={search ? "جرّب تغيير كلمات البحث" : "ستظهر هنا جميع أنشطة المشاريع"}
            className="py-20"
          />
        </div>
      ) : (
        <div className="overflow-hidden rounded-xl border">
          <table className="w-full text-sm">
            <thead className="sticky top-0 z-10 bg-muted/80 backdrop-blur">
              <tr className="border-b">
                <th className="px-4 py-3 text-start font-medium text-muted-foreground">الحدث</th>
                <th className="hidden px-4 py-3 text-start font-medium text-muted-foreground md:table-cell">المشروع</th>
                <th className="hidden px-4 py-3 text-start font-medium text-muted-foreground lg:table-cell">الوصف</th>
                <th className="px-4 py-3 text-start font-medium text-muted-foreground">بواسطة</th>
                <th className="hidden px-4 py-3 text-start font-medium text-muted-foreground sm:table-cell">الوقت</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {items.map((event) => (
                <tr key={event.id} className="transition-colors hover:bg-muted/50">
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-2">
                      <span className="text-sm">{EVENT_ICONS[event.eventType] ?? "📋"}</span>
                      <span className="font-medium">{event.title}</span>
                    </div>
                  </td>
                  <td className="hidden px-4 py-3 text-muted-foreground md:table-cell">
                    {event.project ? (
                      <span>{event.project.name}</span>
                    ) : (
                      <span>—</span>
                    )}
                  </td>
                  <td className="hidden px-4 py-3 text-muted-foreground lg:table-cell">
                    {event.description ?? "—"}
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">{event.actorName}</td>
                  <td className="hidden px-4 py-3 text-muted-foreground sm:table-cell">
                    <span title={formatDateTime(event.createdAt)}>
                      {getRelativeTime(event.createdAt)}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Pagination */}
      {total > 0 && (
        <div className="flex flex-col items-center justify-between gap-3 sm:flex-row">
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <span>عرض</span>
            <select
              value={pageSize}
              onChange={(e) => { setPageSize(Number(e.target.value)); setPage(1); }}
              className="h-7 rounded-md border border-input bg-transparent px-1 text-xs"
              aria-label="عدد العناصر"
            >
              {PAGE_SIZE_OPTIONS.map((s) => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
            <span>من {total} حدث</span>
          </div>
          {totalPages > 1 && (
            <div className="flex items-center gap-1">
              <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page <= 1} aria-label="السابق">
                <ChevronRight className="h-4 w-4" />
              </Button>
              <span className="px-2 text-xs text-muted-foreground">{page} / {totalPages}</span>
              <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={page >= totalPages} aria-label="التالي">
                <ChevronLeft className="h-4 w-4" />
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";

import { accessDeliveryAction } from "@/actions/deliveries/access-delivery";
import { DeliveryPortal } from "@/components/delivery/delivery-portal";
import { PasswordScreen } from "@/components/delivery/password-screen";
import { ExpiredScreen } from "@/components/delivery/expired-screen";
import { DisabledScreen } from "@/components/delivery/disabled-screen";
import type { PublicDeliveryData } from "@/types/delivery";

/* ============================================
   DeliveryPortalAccess — Handles access flow
   1. Calls accessDeliveryAction on mount
   2. Shows password screen if needed
   3. Renders DeliveryPortal with signed URLs
   ============================================ */

type DeliveryPortalAccessProps = {
  slug: string;
};

export function DeliveryPortalAccess({ slug }: DeliveryPortalAccessProps) {
  const [data, setData] = useState<PublicDeliveryData | null>(null);
  const [status, setStatus] = useState<"loading" | "active" | "expired" | "disabled" | "password-required">("loading");
  const [error, setError] = useState("");
  const hasFetched = useRef(false);

  useEffect(() => {
    if (hasFetched.current) return;
    hasFetched.current = true;
    let active = true;
    (async () => {
      const result = await accessDeliveryAction(slug);
      if (!active) return;
      if (result.success && result.data) {
        setData(result.data);
        setStatus("active");
      } else {
        if (result.status === "expired") {
          setStatus("expired");
        } else if (result.status === "disabled") {
          setStatus("disabled");
        } else if (result.status === "password-required") {
          setStatus("password-required");
          setError(result.error ?? "كلمة المرور مطلوبة");
        } else {
          setStatus("disabled");
          setError(result.error ?? "غير متاح");
        }
      }
    })();
    return () => { active = false };
  }, [slug]);

  if (status === "loading") {
    return (
      <main className="flex min-h-dvh items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-muted border-t-primary" />
      </main>
    );
  }

  if (status === "expired") {
    return <ExpiredScreen />;
  }

  if (status === "disabled") {
    return <DisabledScreen />;
  }

  if (status === "password-required") {
    return (
      <PasswordScreen
        slug={slug}
        onSuccess={(d) => {
          setData(d);
          setStatus("active");
        }}
      />
    );
  }

  if (data) {
    return <DeliveryPortal data={data} slug={slug} />;
  }

  return <DisabledScreen />;
}

