/* ============================================
   DeliveryFormModal — Create / Edit delivery
   React Hook Form + Zod
   ============================================ */

type DeliveryFormModalProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  delivery?: DeliveryTableRow | null;
  onSuccess?: () => void;
};

type FormValues = {
  projectId: string;
  title: string;
  expiresAt: string;
  downloadEnabled: boolean;
  allowStreaming: boolean;
  allowComments: boolean;
  passwordProtected: boolean;
  password: string;
  videoIds: string[];
};

type ProjectOption = { id: string; name: string; projectCode: string };
type VideoOption = {
  id: string;
  title: string;
  videoCode: string;
  duration: number | null;
};

export function DeliveryFormModal({
  open,
  onOpenChange,
  delivery,
  onSuccess,
}: DeliveryFormModalProps) {
  const isEdit = !!delivery;
  const [submitting, setSubmitting] = useState(false);
  const [projects, setProjects] = useState<ProjectOption[]>([]);
  const [videos, setVideos] = useState<VideoOption[]>([]);
  const [selectedProject, setSelectedProject] = useState<string>("");
  const [selectedVideos, setSelectedVideos] = useState<string[]>([]);
  const [loadingProjects, setLoadingProjects] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const hasFetched = useRef(false);

  const {
    register,
    handleSubmit,
    reset,
    watch,
    formState: { errors },
  } = useForm<FormValues>({
    resolver: zodResolver(isEdit ? updateDeliverySchema : createDeliverySchema) as never,
    defaultValues: {
      projectId: "",
      title: "",
      expiresAt: "",
      downloadEnabled: true,
      allowStreaming: true,
      allowComments: false,
      passwordProtected: false,
      password: "",
      videoIds: [],
    },
  });

  const watchProjectId = watch("projectId");

  // Fetch projects
  useEffect(() => {
    if (!open || hasFetched.current) return;
    hasFetched.current = true;
    let active = true;
    (async () => {
      const result = await getProjectsAction({ page: 1, pageSize: 100 });
      if (!active) return;
      setProjects(
        result.items.map((p) => ({ id: p.id, name: p.name, projectCode: p.projectCode }))
      );
      setLoadingProjects(false);
    })();
    return () => { active = false };
  }, [open]);

  // Fetch videos when project changes
  useEffect(() => {
    if (!watchProjectId) {
      setVideos([]);
      return;
    }
    let active = true;
    (async () => {
      const result = await getUploadsAction({
        page: 1,
        pageSize: 100,
        projectId: watchProjectId,
        filter: "ready",
      });
      if (!active) return;
      setVideos(
        result.items.map((v) => ({
          id: v.id,
          title: v.title,
          videoCode: v.videoCode,
          duration: v.duration,
        }))
      );
    })();
    return () => { active = false };
  }, [watchProjectId]);

  // Populate form when editing
  useEffect(() => {
    if (delivery) {
      // Fetch delivery videos
      let active = true;
      (async () => {
        // We'd fetch delivery details, but for simplicity use the videoIds from the form
      })();
      reset({
        projectId: delivery.projectId,
        title: delivery.title,
        expiresAt: delivery.expiresAt
          ? new Date(delivery.expiresAt).toISOString().slice(0, 16)
          : "",
        downloadEnabled: delivery.downloadEnabled,
        allowStreaming: delivery.allowStreaming,
        allowComments: false,
        passwordProtected: delivery.passwordProtected,
        password: "",
        videoIds: [],
      });
      setSelectedProject(delivery.projectId);
    } else {
      reset({
        projectId: "",
        title: "",
        expiresAt: "",
        downloadEnabled: true,
        allowStreaming: true,
        allowComments: false,
        passwordProtected: false,
        password: "",
        videoIds: [],
      });
      setSelectedVideos([]);
    }
  }, [delivery, reset]);

  const toggleVideo = (videoId: string) => {
    setSelectedVideos((prev) =>
      prev.includes(videoId)
        ? prev.filter((v) => v !== videoId)
        : [...prev, videoId]
    );
  };

  const onSubmit = async (data: FormValues) => {
    setSubmitting(true);
    const formData = new FormData();
    formData.append("projectId", data.projectId);
    formData.append("title", data.title);
    formData.append("expiresAt", new Date(data.expiresAt).toISOString());
    formData.append("downloadEnabled", String(data.downloadEnabled));
    formData.append("allowStreaming", String(data.allowStreaming));
    formData.append("allowComments", String(data.allowComments));
    formData.append("passwordProtected", String(data.passwordProtected));
    formData.append("password", data.password || "");
    for (const vid of selectedVideos) {
      formData.append("videoIds", vid);
    }

    try {
      if (isEdit && delivery) {
        const result: UpdateDeliveryState = await updateDeliveryAction(
          delivery.id,
          { success: false },
          formData
        );
        if (result.success) {
          onOpenChange(false);
          onSuccess?.();
        }
      } else {
        const result: CreateDeliveryState = await createDeliveryAction(
          { success: false },
          formData
        );
        if (result.success) {
          onOpenChange(false);
          onSuccess?.();
        }
      }
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-h-[90vh] overflow-y-auto sm:max-w-[560px]">
        <DialogHeader>
          <DialogTitle>{isEdit ? "تعديل التسليم" : "إنشاء تسليم جديد"}</DialogTitle>
          <DialogDescription>
            {isEdit ? "قم بتحديث بيانات التسليم" : "أنشئ تسليماً جديداً للعميل"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
          {/* Project */}
          <div className="space-y-1.5">
            <Label htmlFor="projectId">المشروع <span className="text-destructive">*</span></Label>
            <select
              id="projectId"
              className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
              {...register("projectId")}
              disabled={loadingProjects || isEdit}
            >
              <option value="">{loadingProjects ? "جاري التحميل..." : "اختر المشروع"}</option>
              {projects.map((p) => (
                <option key={p.id} value={p.id}>{p.name} ({p.projectCode})</option>
              ))}
            </select>
          </div>

          {/* Title */}
          <div className="space-y-1.5">
            <Label htmlFor="title">عنوان التسليم <span className="text-destructive">*</span></Label>
            <Input id="title" placeholder="عنوان التسليم" {...register("title")} />
          </div>

          {/* Expiration */}
          <div className="space-y-1.5">
            <Label htmlFor="expiresAt">تاريخ الانتهاء <span className="text-destructive">*</span></Label>
            <Input id="expiresAt" type="datetime-local" {...register("expiresAt")} />
          </div>

          {/* Toggles */}
          <div className="grid grid-cols-2 gap-3">
            <label className="flex items-center gap-2 text-sm">
              <input type="checkbox" className="rounded" {...register("downloadEnabled")} />
              تفعيل التحميل
            </label>
            <label className="flex items-center gap-2 text-sm">
              <input type="checkbox" className="rounded" {...register("allowStreaming")} />
              السماح بالبث
            </label>
            <label className="flex items-center gap-2 text-sm">
              <input type="checkbox" className="rounded" {...register("allowComments")} />
              السماح بالتعليقات
            </label>
            <label className="flex items-center gap-2 text-sm">
              <input type="checkbox" className="rounded" {...register("passwordProtected")} />
              حماية بكلمة مرور
            </label>
          </div>

          {/* Password */}
          {watch("passwordProtected") && (
            <div className="space-y-1.5">
              <Label htmlFor="password">كلمة المرور</Label>
              <div className="relative">
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  placeholder="أدخل كلمة المرور"
                  className="pe-10"
                  {...register("password")}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword((s) => !s)}
                  className="absolute end-2 top-1/2 -translate-y-1/2 text-muted-foreground"
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
            </div>
          )}

          {/* Video Selection */}
          {watchProjectId && (
            <div className="space-y-2">
              <Label>الفيديوهات <span className="text-destructive">*</span></Label>
              {videos.length === 0 ? (
                <p className="text-xs text-muted-foreground py-4 text-center">
                  لا توجد فيديوهات جاهزة في هذا المشروع
                </p>
              ) : (
                <div className="max-h-40 space-y-1 overflow-y-auto rounded-md border p-2">
                  {videos.map((v) => (
                    <label
                      key={v.id}
                      className="flex cursor-pointer items-center gap-2 rounded p-1.5 text-sm hover:bg-muted/50"
                    >
                      <input
                        type="checkbox"
                        checked={selectedVideos.includes(v.id)}
                        onChange={() => toggleVideo(v.id)}
                        className="rounded"
                      />
                      <Video className="h-3.5 w-3.5 text-muted-foreground" />
                      <span className="truncate">{v.title}</span>
                      <span className="ms-auto font-mono text-xs text-muted-foreground">{v.videoCode}</span>
                    </label>
                  ))}
                </div>
              )}
            </div>
          )}

          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={submitting}>
              إلغاء
            </Button>
            <Button type="submit" disabled={submitting}>
              {submitting && <Loader2 className="h-4 w-4 animate-spin" />}
              {isEdit ? "حفظ التغييرات" : "إنشاء التسليم"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2 } from "lucide-react";

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  createClientSchema,
  updateClientSchema,
  type CreateClientInput,
} from "@/lib/validations/client";
import { createClientAction, type CreateClientState } from "@/actions/clients/create-client";
import { updateClientAction, type UpdateClientState } from "@/actions/clients/update-client";
import type { ClientTableRow } from "@/types/client";

/* ============================================
   ClientFormModal — Create / Edit client
   React Hook Form + Zod
   ============================================ */

type ClientFormModalProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  client?: ClientTableRow | null;
  onSuccess?: () => void;
};

const STATUS_OPTIONS = [
  { value: "ACTIVE", label: "نشط" },
  { value: "BLOCKED", label: "محظور" },
] as const;

export function ClientFormModal({
  open,
  onOpenChange,
  client,
  onSuccess,
}: ClientFormModalProps) {
  const isEdit = !!client;

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<CreateClientInput>({
    resolver: zodResolver(isEdit ? updateClientSchema : createClientSchema),
    defaultValues: {
      name: "",
      company: "",
      email: "",
      phone: "",
      notes: "",
      status: "ACTIVE",
    },
  });

  // Populate form when editing
  useEffect(() => {
    if (client) {
      reset({
        name: client.name,
        company: client.company ?? "",
        email: client.email,
        phone: client.phone ?? "",
        notes: client.notes ?? "",
        status: client.status === "ARCHIVED" ? "ACTIVE" : client.status,
      });
    } else {
      reset({
        name: "",
        company: "",
        email: "",
        phone: "",
        notes: "",
        status: "ACTIVE",
      });
    }
  }, [client, reset]);

  const onSubmit = async (data: CreateClientInput) => {
    const formData = new FormData();
    formData.append("name", data.name);
    formData.append("company", data.company ?? "");
    formData.append("email", data.email);
    formData.append("phone", data.phone ?? "");
    formData.append("notes", data.notes ?? "");
    formData.append("status", data.status);

    if (isEdit && client) {
      const result: UpdateClientState = await updateClientAction(
        client.id,
        { success: false },
        formData
      );
      if (result.success) {
        onOpenChange(false);
        onSuccess?.();
      }
    } else {
      const result: CreateClientState = await createClientAction(
        { success: false },
        formData
      );
      if (result.success) {
        onOpenChange(false);
        onSuccess?.();
      }
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-h-[90vh] overflow-y-auto sm:max-w-[480px]">
        <DialogHeader>
          <DialogTitle>{isEdit ? "تعديل العميل" : "إضافة عميل جديد"}</DialogTitle>
          <DialogDescription>
            {isEdit
              ? "قم بتحديث بيانات العميل"
              : "أدخل بيانات العميل الجديد"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
          {/* Name */}
          <div className="space-y-1.5">
            <Label htmlFor="name">
              الاسم <span className="text-destructive">*</span>
            </Label>
            <Input
              id="name"
              placeholder="اسم العميل"
              aria-invalid={!!errors.name}
              aria-describedby={errors.name ? "name-error" : undefined}
              {...register("name")}
            />
            {errors.name && (
              <p id="name-error" className="text-xs text-destructive" role="alert">
                {errors.name.message}
              </p>
            )}
          </div>

          {/* Company */}
          <div className="space-y-1.5">
            <Label htmlFor="company">الشركة</Label>
            <Input
              id="company"
              placeholder="اسم الشركة (اختياري)"
              {...register("company")}
            />
          </div>

          {/* Email */}
          <div className="space-y-1.5">
            <Label htmlFor="email">
              البريد الإلكتروني <span className="text-destructive">*</span>
            </Label>
            <Input
              id="email"
              type="email"
              dir="ltr"
              className="text-end"
              placeholder="client@example.com"
              aria-invalid={!!errors.email}
              aria-describedby={errors.email ? "email-error" : undefined}
              {...register("email")}
            />
            {errors.email && (
              <p id="email-error" className="text-xs text-destructive" role="alert">
                {errors.email.message}
              </p>
            )}
          </div>

          {/* Phone */}
          <div className="space-y-1.5">
            <Label htmlFor="phone">رقم الهاتف</Label>
            <Input
              id="phone"
              dir="ltr"
              className="text-end"
              placeholder="05xxxxxxxx"
              aria-invalid={!!errors.phone}
              aria-describedby={errors.phone ? "phone-error" : undefined}
              {...register("phone")}
            />
            {errors.phone && (
              <p id="phone-error" className="text-xs text-destructive" role="alert">
                {errors.phone.message}
              </p>
            )}
          </div>

          {/* Status */}
          <div className="space-y-1.5">
            <Label htmlFor="status">الحالة</Label>
            <select
              id="status"
              className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
              {...register("status")}
            >
              {STATUS_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
          </div>

          {/* Notes */}
          <div className="space-y-1.5">
            <Label htmlFor="notes">ملاحظات</Label>
            <textarea
              id="notes"
              rows={3}
              placeholder="ملاحظات إضافية (اختياري)"
              className="flex w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm shadow-sm transition-colors placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
              {...register("notes")}
            />
            {errors.notes && (
              <p className="text-xs text-destructive" role="alert">
                {errors.notes.message}
              </p>
            )}
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
            >
              إلغاء
            </Button>
            <Button type="submit" disabled={false}>
              <Loader2 className="hidden" />
              {isEdit ? "حفظ التغييرات" : "إضافة العميل"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2 } from "lucide-react";

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  createProjectSchema,
  updateProjectSchema,
} from "@/lib/validations/project";
import { createProjectAction, type CreateProjectState } from "@/actions/projects/create-project";
import { updateProjectAction, type UpdateProjectState } from "@/actions/projects/update-project";
import { getClientsAction } from "@/actions/clients/get-clients";
import type { ProjectTableRow } from "@/types/project";

/* ============================================
   ProjectFormModal — Create / Edit project
   React Hook Form + Zod
   ============================================ */

type ProjectFormModalProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  project?: ProjectTableRow | null;
  onSuccess?: () => void;
};

/** Form values — deadline is string for datetime-local input. */
type ProjectFormValues = {
  clientId: string;
  name: string;
  description?: string;
  retentionPeriod: "TWENTY_FOUR_HOURS" | "FORTY_EIGHT_HOURS" | "SEVENTY_TWO_HOURS" | "SEVEN_DAYS" | "CUSTOM";
  deadline: string;
  status: "DRAFT" | "IN_PROGRESS" | "READY" | "DOWNLOAD_ENABLED" | "COMPLETED" | "ARCHIVED";
};

const STATUS_OPTIONS = [
  { value: "DRAFT", label: "مسودة" },
  { value: "IN_PROGRESS", label: "قيد التنفيذ" },
  { value: "READY", label: "جاهز" },
  { value: "DOWNLOAD_ENABLED", label: "التحميل مفعّل" },
  { value: "COMPLETED", label: "مكتمل" },
] as const;

const RETENTION_OPTIONS = [
  { value: "TWENTY_FOUR_HOURS", label: "24 ساعة" },
  { value: "FORTY_EIGHT_HOURS", label: "48 ساعة" },
  { value: "SEVENTY_TWO_HOURS", label: "72 ساعة" },
  { value: "SEVEN_DAYS", label: "7 أيام" },
  { value: "CUSTOM", label: "مخصص" },
] as const;

type ClientOption = {
  id: string;
  name: string;
  clientCode: string;
};

export function ProjectFormModal({
  open,
  onOpenChange,
  project,
  onSuccess,
}: ProjectFormModalProps) {
  const isEdit = !!project;
  const [submitting, setSubmitting] = useState(false);
  const [clients, setClients] = useState<ClientOption[]>([]);
  const [loadingClients, setLoadingClients] = useState(true);
  const hasFetched = useRef(false);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<ProjectFormValues>({
    resolver: zodResolver(isEdit ? updateProjectSchema : createProjectSchema) as never,
    defaultValues: {
      clientId: "",
      name: "",
      description: "",
      retentionPeriod: "TWENTY_FOUR_HOURS",
      deadline: "",
      status: "DRAFT",
    },
  });

  // Fetch active clients for dropdown (once on first open)
  useEffect(() => {
    if (!open || hasFetched.current) return;
    hasFetched.current = true;
    let active = true;
    (async () => {
      const result = await getClientsAction({ page: 1, pageSize: 100, filter: "active" });
      if (!active) return;
      setClients(
        result.items.map((c) => ({
          id: c.id,
          name: c.name,
          clientCode: c.clientCode,
        }))
      );
      setLoadingClients(false);
    })();
    return () => { active = false };
  }, [open]);

  // Populate form when editing
  useEffect(() => {
    if (project) {
      reset({
        clientId: project.clientId,
        name: project.name,
        description: project.description ?? "",
        retentionPeriod: project.retentionPeriod,
        deadline: project.deadline
          ? new Date(project.deadline).toISOString().slice(0, 16)
          : "",
        status: project.status === "ARCHIVED" ? "DRAFT" : project.status,
      });
    } else {
      reset({
        clientId: "",
        name: "",
        description: "",
        retentionPeriod: "TWENTY_FOUR_HOURS",
        deadline: "",
        status: "DRAFT",
      });
    }
  }, [project, reset]);

  const onSubmit = async (data: ProjectFormValues) => {
    setSubmitting(true);
    const formData = new FormData();
    formData.append("clientId", data.clientId);
    formData.append("name", data.name);
    formData.append("description", data.description ?? "");
    formData.append("retentionPeriod", data.retentionPeriod);
    formData.append("deadline", new Date(data.deadline).toISOString());
    formData.append("status", data.status);

    try {
      if (isEdit && project) {
        const result: UpdateProjectState = await updateProjectAction(
          project.id,
          { success: false },
          formData
        );
        if (result.success) {
          onOpenChange(false);
          onSuccess?.();
        }
      } else {
        const result: CreateProjectState = await createProjectAction(
          { success: false },
          formData
        );
        if (result.success) {
          onOpenChange(false);
          onSuccess?.();
        }
      }
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-h-[90vh] overflow-y-auto sm:max-w-[520px]">
        <DialogHeader>
          <DialogTitle>{isEdit ? "تعديل المشروع" : "إضافة مشروع جديد"}</DialogTitle>
          <DialogDescription>
            {isEdit
              ? "قم بتحديث بيانات المشروع"
              : "أدخل بيانات المشروع الجديد"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
          {/* Client */}
          <div className="space-y-1.5">
            <Label htmlFor="clientId">
              العميل <span className="text-destructive">*</span>
            </Label>
            <select
              id="clientId"
              className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
              {...register("clientId")}
              aria-invalid={!!errors.clientId}
              aria-describedby={errors.clientId ? "clientId-error" : undefined}
              disabled={loadingClients}
            >
              <option value="">
                {loadingClients ? "جاري التحميل..." : "اختر العميل"}
              </option>
              {clients.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.name} ({c.clientCode})
                </option>
              ))}
            </select>
            {errors.clientId && (
              <p id="clientId-error" className="text-xs text-destructive" role="alert">
                {errors.clientId.message}
              </p>
            )}
          </div>

          {/* Name */}
          <div className="space-y-1.5">
            <Label htmlFor="name">
              اسم المشروع <span className="text-destructive">*</span>
            </Label>
            <Input
              id="name"
              placeholder="اسم المشروع"
              aria-invalid={!!errors.name}
              aria-describedby={errors.name ? "name-error" : undefined}
              {...register("name")}
            />
            {errors.name && (
              <p id="name-error" className="text-xs text-destructive" role="alert">
                {errors.name.message}
              </p>
            )}
          </div>

          {/* Description */}
          <div className="space-y-1.5">
            <Label htmlFor="description">الوصف</Label>
            <textarea
              id="description"
              rows={3}
              placeholder="وصف المشروع (اختياري)"
              className="flex w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm shadow-sm transition-colors placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
              {...register("description")}
            />
            {errors.description && (
              <p className="text-xs text-destructive" role="alert">
                {errors.description.message}
              </p>
            )}
          </div>

          {/* Retention Period */}
          <div className="space-y-1.5">
            <Label htmlFor="retentionPeriod">فترة الاحتفاظ</Label>
            <select
              id="retentionPeriod"
              className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
              {...register("retentionPeriod")}
            >
              {RETENTION_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
          </div>

          {/* Deadline */}
          <div className="space-y-1.5">
            <Label htmlFor="deadline">
              الموعد النهائي <span className="text-destructive">*</span>
            </Label>
            <Input
              id="deadline"
              type="datetime-local"
              aria-invalid={!!errors.deadline}
              aria-describedby={errors.deadline ? "deadline-error" : undefined}
              {...register("deadline")}
            />
            {errors.deadline && (
              <p id="deadline-error" className="text-xs text-destructive" role="alert">
                {errors.deadline.message}
              </p>
            )}
          </div>

          {/* Status */}
          <div className="space-y-1.5">
            <Label htmlFor="status">الحالة</Label>
            <select
              id="status"
